1	import { readFile, writeFile } from "node:fs/promises";
2	import type { ComputedIssue, Event, IssueId, IssueStatus, UpdateEvent } from "../types";
3	
4	/**
5	 * Append a single event to an issue's JSON file (array of events).
6	 * Creates the file with a JSON array if it doesn't exist yet.
7	 */
8	export async function appendEvent(issuePath: string, event: Event): Promise<void> {
9	  let events: Event[];
10	
11	  try {
12	    const contents = await readFile(issuePath, "utf-8");
13	    events = JSON.parse(contents) as Event[];
14	  } catch {
15	    events = [];
16	  }
17	
18	  events.push(event);
19	  await writeFile(issuePath, `${JSON.stringify(events, null, 2)}\n`, "utf-8");
20	}
21	
22	/**
23	 * Read an issue file and return the raw event array.
24	 */
25	export async function replayEvents(issuePath: string): Promise<Event[]> {
26	  const contents = await readFile(issuePath, "utf-8");
27	  return JSON.parse(contents) as Event[];
28	}
29	
30	/** Default values for a new issue (no events applied yet). */
31	const DEFAULTS = {
32	  status: "idea" as IssueStatus,
33	  priority: 3 as 1 | 2 | 3 | 4 | 5,
34	  assignee: null as string | null,
35	  parentId: null as string | null,
36	  tags: [] as string[],
37	  description: "",
38	};
39	
40	/** Mutable state being built during event replay. */
41	interface IssueState {
42	  title: string;
43	  description: string;
44	  status: IssueStatus;
45	  priority: 1 | 2 | 3 | 4 | 5;
46	  assignee: string | null;
47	  parentId: string | null;
48	  tags: string[];
49	}
50	
51	/**
52	 * Apply an update event's content to the mutable state.
53	 */
54	function applyUpdate(state: IssueState, content: UpdateEvent["content"]): void {
55	  if (content.title !== undefined) state.title = content.title;
56	  if (content.description !== undefined) state.description = content.description;
57	  if (content.status !== undefined) state.status = content.status;
58	  if (content.priority !== undefined) state.priority = content.priority;
59	  if (content.assignee !== undefined) state.assignee = content.assignee;
60	  if (content.parentId !== undefined) state.parentId = content.parentId;
61	  if (content.tags !== undefined) state.tags = content.tags;
62	}
63	
64	/**
65	 * Replay events to produce a ComputedIssue.
66	 *
67	 * - Creation event: sets createdAt, createdBy.
68	 * - Update events: merge content fields into properties.
69	 * - Comment / blockage events: ignored (handled separately).
70	 * - updatedAt = timestamp of last event.
71	 *
72	 * The `id` comes from the filename, not from the events.
73	 */
74	export function computeState(events: Event[], issueId: IssueId): ComputedIssue {
75	  const state: IssueState = {
76	    title: "",
77	    description: DEFAULTS.description,
78	    status: DEFAULTS.status,
79	    priority: DEFAULTS.priority,
80	    assignee: DEFAULTS.assignee,
81	    parentId: DEFAULTS.parentId,
82	    tags: [...DEFAULTS.tags],
83	  };
84	
85	  let createdAt = "";
86	  let createdBy = "";
87	  let updatedAt = "";
88	
89	  for (const event of events) {
90	    updatedAt = event.timestamp;
91	
92	    if (event.type === "creation") {
93	      createdAt = event.timestamp;
94	      createdBy = event.author;
95	    } else if (event.type === "update") {
96	      applyUpdate(state, event.content);
97	    }
98	    // Comment and blockage events are metadata-only — skip
99	  }
100	
101	  return {
102	    id: issueId,
103	    ...state,
104	    createdAt,
105	    createdBy,
106	    updatedAt,
107	  };
108	}
