400	   * Get the raw event history for an issue.
401	   */
402	  async history(id: IssueId): Promise<HistoryResult> {
403	    const trackerDir = resolveTrackerDir(this.cwd);
404	    if (!trackerDir) {
405	      throw new TrackgenticError(
406	        ErrorCodes.NOT_INITIALIZED.result,
407	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
408	        ErrorCodes.NOT_INITIALIZED.exitCode,
409	      );
410	    }
411	
412	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
413	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
414	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
415	    if (authResult instanceof TrackgenticError) {
416	      throw authResult;
417	    }
418	
419	    const index = await readIndex(trackerDir);
420	    const entry = findEntry(index, id);
421	    if (!entry) {
422	      throw new TrackgenticError(
423	        ErrorCodes.NOT_FOUND.result,
424	        `Issue ${id} not found in index.`,
425	        ErrorCodes.NOT_FOUND.exitCode,
426	      );
427	    }
428	
429	    const issueFilePath = join(trackerDir, entry.path);
430	    if (!existsSync(issueFilePath)) {
431	      throw new TrackgenticError(
432	        ErrorCodes.ISSUE_MISSING.result,
433	        `Issue file for ${id} is missing.`,
434	        ErrorCodes.ISSUE_MISSING.exitCode,
435	      );
436	    }
437	
438	    return replayEvents(issueFilePath);
439	  }
440	
441	  // ─── User Management ──────────────────────────────────────────────
442	
443	  /**
444	   * Register a new user. Does NOT require auth (bootstrap mechanism).
445	   */
446	  async usersRegister(name: string): Promise<UsersRegisterResult> {
447	    const trackerDir = resolveTrackerDir(this.cwd);
448	    if (!trackerDir) {
449	      throw new TrackgenticError(
450	        ErrorCodes.NOT_INITIALIZED.result,
451	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
452	        ErrorCodes.NOT_INITIALIZED.exitCode,
453	      );
454	    }
455	
456	    const lowerName = name.toLowerCase();
457	
458	    // Reject reserved name
459	    if (lowerName === "anonymous") {
460	      return {
461	        result: "USER_ALREADY_EXISTS",
462	        message: `"anonymous" is a reserved name and cannot be registered.`,
463	      };
464	    }
465	
466	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
467	
468	    // Check uniqueness
469	    if (users.users.find((u) => u.name === lowerName)) {
470	      return {
471	        result: "USER_ALREADY_EXISTS",
472	        message: `User "${lowerName}" already exists.`,
473	      };
474	    }
475	
476	    const token = generateToken();
477	    const newUser: UserEntry = {
478	      name: lowerName,
479	      token,
480	      registeredAt: new Date().toISOString(),
481	    };
482	
483	    users.users.push(newUser);
484	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
485	
486	    return { result: "OK", name: lowerName, token };
487	  }
488	
489	  /**
490	   * List all registered users (tokens stripped).
491	   * Auth: depends on mode (read operation).
492	   */
493	  async usersList(): Promise<UsersListResult> {
494	    const trackerDir = resolveTrackerDir(this.cwd);
495	    if (!trackerDir) {
496	      throw new TrackgenticError(
497	        ErrorCodes.NOT_INITIALIZED.result,
498	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
499	        ErrorCodes.NOT_INITIALIZED.exitCode,
500	      );
501	    }
502	
503	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
504	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
505	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
506	    if (authResult instanceof TrackgenticError) {
507	      throw authResult;
508	    }
509	
510	    return users.users.map((u) => ({
511	      name: u.name,
512	      registeredAt: u.registeredAt,
513	    }));
514	  }
515	
516	  /**
517	   * Revoke (remove) a user. Requires auth (write operation).
518	   */
519	  async usersRevoke(name: string): Promise<UsersRevokeResult> {
520	    const trackerDir = resolveTrackerDir(this.cwd);
521	    if (!trackerDir) {
522	      throw new TrackgenticError(
523	        ErrorCodes.NOT_INITIALIZED.result,
524	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
525	        ErrorCodes.NOT_INITIALIZED.exitCode,
526	      );
527	    }
528	
529	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
530	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
531	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
532	    if (authResult instanceof TrackgenticError) {
533	      throw authResult;
534	    }
535	
536	    const lowerName = name.toLowerCase();
537	    const userIndex = users.users.findIndex((u) => u.name === lowerName);
538	    if (userIndex === -1) {
539	      return {
540	        result: "USER_NOT_FOUND",
541	        message: `User "${lowerName}" not found.`,
542	      };
543	    }
544	
545	    users.users.splice(userIndex, 1);
546	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
547	
548	    return { result: "OK" };
549	  }
550	
551	  /**
552	   * Regenerate a user's token. Self-service only — caller must be the target user.
553	   * Requires auth (write operation).
554	   */
555	  async usersRegenerate(name: string): Promise<UsersRegenerateResult> {
556	    const trackerDir = resolveTrackerDir(this.cwd);
557	    if (!trackerDir) {
558	      throw new TrackgenticError(
559	        ErrorCodes.NOT_INITIALIZED.result,
560	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
561	        ErrorCodes.NOT_INITIALIZED.exitCode,
562	      );
563	    }
564	
565	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
566	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
567	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
568	    if (authResult instanceof TrackgenticError) {
569	      throw authResult;
570	    }
571	
572	    const callerName = authResult.author;
573	    const lowerName = name.toLowerCase();
574	
575	    // Self-service check: caller must be the target user
576	    if (callerName !== lowerName) {
577	      return {
578	        result: "INVALID_TOKEN",
579	        message: `You can only regenerate your own token.`,
580	      };
581	    }
582	
583	    const user = users.users.find((u) => u.name === lowerName);
584	    if (!user) {
585	      return {
586	        result: "USER_NOT_FOUND",
587	        message: `User "${lowerName}" not found.`,
588	      };
589	    }
590	
591	    const newToken = generateToken();
592	    user.token = newToken;
593	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
594	
595	    return { result: "OK", name: lowerName, token: newToken };
596	  }
597	}
