70	/**
71	 * Handler for the `trackgentic users regenerate <name>` command.
72	 */
73	export async function usersRegenerateAction(name: string): Promise<void> {
74	  try {
75	    const tracker = new Tracker();
76	    const result = await tracker.usersRegenerate(name);
77	    if (result instanceof TrackgenticError) {
78	      writeStderr({ result: result.result, message: result.message });
79	      process.exit(result.exitCode);
80	    }
81	    if ("result" in result && result.result !== "OK") {
82	      writeStderr(result);
83	      if (result.result === "USER_NOT_FOUND") process.exit(9);
84	      if (result.result === "INVALID_TOKEN") process.exit(3);
85	      process.exit(1);
86	    }
87	    writeStdout(result);
88	    process.exit(0);
89	  } catch (err) {
90	    if (err instanceof TrackgenticError) {
91	      writeStderr({ result: err.result, message: err.message });
92	      process.exit(err.exitCode);
93	    }
94	    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
95	    process.exit(1);
96	  }
97	}
